solution_code:
#include <iostream>

int main() {
    int n;
    std::cin >> n;

    const char* result =
        ((n % 3 == 0) && (n % 5 == 0)) ? "FizzBuzz" :
        (n % 3 == 0)                    ? "Fizz" :
        (n % 5 == 0)                    ? "Buzz" : nullptr;

    if (result) {
        std::cout << result << "\n";
    } else {
        std::cout << n << "\n";
    }
    return 0;
}

