solution_code:
#include <iostream>

int main() {
    int a, b;
    std::cin >> a >> b;

    if (b == 0) {
        std::cout << "undefined\n";
    } else {
        std::cout << static_cast<double>(a) / b << "\n";
    }
    return 0;
}
